import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY
});

// Flowise Chatflow configuration
export const chatflowConfig = {
  flowData: {
    nodes: {
      trigger: {
        type: 'trigger',
        data: {
          callbacks: {
            onStart: async (input: any) => {
              await vex.checkpoint('workflow_trigger', {
                input,
                metadata: { workflow_id: input.workflowId }
              });
            }
          }
        }
      }
    }
  }
};

// Custom Tool Node in Flowise
const apiToolNode = {
  type: 'tool',
  data: {
    func: async (input: any) => {
      const checkpoint = await vex.checkpoint('api_tool_call', {
        action: 'create_order',
        params: input,
        idempotencyKey: input.orderId,
        verify: {
          correctness: {
            schema: {
              type: 'object',
              properties: { status: { const: 'success' } }
            }
          }
        }
      });

      if (!checkpoint.passed) {
        throw new Error('Action verification failed');
      }

      return await fetch('/api/orders', {
        method: 'POST',
        body: JSON.stringify(input),
        headers: { 'Idempotency-Key': input.orderId }
      });
    }
  }
};

// Conditional Logic Node
const conditionalNode = {
  type: 'condition',
  data: {
    condition: async (input: any) => {
      const result = await vex.checkpoint('permission_check', {
        action: 'high_risk_branch',
        userId: input.userId,
        requiredRole: 'admin',
        verify: {
          permission: {
            roles: ['admin', 'manager'],
            userId: input.userId
          }
        }
      });

      return result.passed ? 'approved_branch' : 'rejected_branch';
    }
  }
};

// Human Approval Node with Rollback
const approvalNode = {
  type: 'human-approval',
  data: {
    onApprove: async (input: any) => {
      // Track successful execution for rollback
      await vex.checkpoint('action_executed', {
        action: 'process_payment',
        transactionId: input.txId,
        rollbackEnabled: true,
        state: { amount: input.amount, status: 'completed' }
      });
      return { status: 'approved', txId: input.txId };
    },
    onReject: async (input: any) => {
      // Trigger rollback if partially executed
      await vex.rollback('process_payment', { transactionId: input.txId });
      return { status: 'rolled_back' };
    }
  }
};

