// flowise-vex-handler.ts
import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ projectId: 'flowise-prod' });

// Global callback for all Flowise executions
export const vexCallbackHandler = {
  onChatFlowStart: async (data: any) => {
    await vex.checkpoint('flow_start', {
      flowId: data.flowId,
      input: data.input,
      riskProfile: 'medium'
    });
  },

  onNodeExecute: async (nodeData: any) => {
    await vex.checkpoint(`node_${nodeData.nodeId}`, {
      nodeType: nodeData.type,
      input: nodeData.input,
      output: nodeData.output
    });
  },

  onChatFlowEnd: async (result: any) => {
    await vex.checkpoint('flow_complete', {
      success: result.success,
      finalOutput: result.output
    });
  }
};

// Register in Flowise server
export default vexCallbackHandler;

// Vector Store Node wrapper
const ragMonitor = async (retrievedDocs: any[], query: string) => {
  const checkpoint = await vex.checkpoint('rag_retrieval', {
    query,
    docs: retrievedDocs.map(d => ({ content: d.pageContent, score: d.metadata.score })),
    verify: {
      relevance: {
        minScore: 0.7,
        semanticThreshold: 0.8,
        maxDocs: 5
      }
    }
  });

  if (!checkpoint.passed) {
    console.warn('Low relevance docs filtered:', checkpoint.failures);
    return retrievedDocs.filter(doc => doc.metadata.score > 0.7);
  }

  return retrievedDocs;
};

// Multi-agent handoff verification
const handoffVerifier = async (fromAgent: string, toAgent: string, context: any) => {
  const result = await vex.checkpoint('agent_handoff', {
    from: fromAgent,
    to: toAgent,
    contextKeys: Object.keys(context),
    requiredKeys: ['userId', 'sessionId', 'workflowState'],
    verify: {
      contextIntegrity: {
        requiredFields: ['userId', 'sessionId'],
        maxAgeMinutes: 30
      }
    }
  });

  return result.passed ? context : null;
};
